class User:
    def __init__(self, id, role):
        self.id = id
        self.role = role


class CartItem:
    def __init__(self, product_id, quantity, price):
        self.product_id = product_id
        self.quantity = quantity
        self.price = price


class DiscountCode:
    def __init__(self, code, description, admin_only=False, user_tier=None):
        self.code = code
        self.description = description
        self.admin_only = admin_only
        self.user_tier = user_tier


def validate_cart_items(cart_items, user):
    for item in cart_items:
        if item.quantity < 1 or item.price <= 0:
            return False
    return True


def apply_discount_codes(cart_items, discount_codes, user):
    applied_discounts = []
    for code in discount_codes:
        if (code.admin_only and user.role != 'admin') or (code.user_tier and user.id not in code.user_tier):
            continue
        for item in cart_items:
            item.price *= 0.9  # hardcoded 10% discount
            applied_discounts.append(code.code)
    return cart_items, applied_discounts


def calculate_tax(cart_items):
    total = sum(item.price * item.quantity for item in cart_items)
    tax_rate = 0.08  # hardcoded 8% tax rate
    return total * tax_rate


def process_payment(total_cost, payment_method):
    if payment_method == 'credit_card':
        print("Processing credit card payment...")
    elif payment_method == 'paypal':
        print("Processing PayPal payment...")
    else:
        raise ValueError("Unsupported payment method")


def create_order_record(cart_items, applied_discounts, tax_amount, total_cost, user):
    order = {
        'cart_items': cart_items,
        'applied_discounts': applied_discounts,
        'tax_amount': tax_amount,
        'total_cost': total_cost,
        'user_id': user.id
    }
    return order


def checkout_process(cart_items, discount_codes, payment_method, user):
    if not validate_cart_items(cart_items, user):
        raise ValueError("Invalid cart items")

    cart_items, applied_discounts = apply_discount_codes(cart_items, discount_codes, user)
    tax_amount = calculate_tax(cart_items)
    total_cost = sum(item.price * item.quantity for item in cart_items) + tax_amount

    process_payment(total_cost, payment_method)

    order_record = create_order_record(cart_items, applied_discounts, tax_amount, total_cost, user)
    return order_record


